$ErrorActionPreference = "Stop"

$project = "C:\Users\arauj\grafica-flash"

if (!(Test-Path -LiteralPath $project)) {
  Write-Host "Projeto nao encontrado em $project" -ForegroundColor Red
  exit 1
}

Set-Location -LiteralPath $project

$utf8NoBom = New-Object System.Text.UTF8Encoding($false)

function Write-Base64File($relativePath, $base64Content) {
  $target = Join-Path $project $relativePath
  $directory = Split-Path $target -Parent
  New-Item -ItemType Directory -Force -Path $directory | Out-Null

  if (Test-Path -LiteralPath $target) {
    $backup = $target + ".backup-site-publico-v5-" + (Get-Date -Format "yyyyMMddHHmmss")
    Copy-Item -LiteralPath $target -Destination $backup -Force
    Write-Host "Backup: $backup" -ForegroundColor DarkYellow
  }

  $bytes = [System.Convert]::FromBase64String($base64Content.Trim())
  $content = [System.Text.Encoding]::UTF8.GetString($bytes)
  [System.IO.File]::WriteAllText($target, $content, $utf8NoBom)

  Write-Host "Criado/atualizado: $relativePath" -ForegroundColor Green
}

Write-Base64File "app\api\public-site\[slug]\route.ts" @"

"@

Write-Base64File "app\site\[slug]\page.tsx" @"

"@

Write-Base64File "app\painel\site\page.tsx" @"

"@

Write-Base64File "app\loja\[slug]\page.tsx" @"

"@

# Ajusta links antigos em painel/admin para abrir /site/[slug] em vez de /loja/ ou /orcamento/.
$paths = @("app\painel", "app\admin")
foreach ($folder in $paths) {
  if (Test-Path -LiteralPath $folder) {
    Get-ChildItem -LiteralPath $folder -Recurse -File -Include *.tsx,*.ts | ForEach-Object {
      $content = [System.IO.File]::ReadAllText($_.FullName)
      $new = $content.Replace("/orcamento/", "/site/").Replace("/loja/", "/site/")
      if ($new -ne $content) {
        $backup = $_.FullName + ".backup-site-link-" + (Get-Date -Format "yyyyMMddHHmmss")
        Copy-Item -LiteralPath $_.FullName -Destination $backup -Force
        [System.IO.File]::WriteAllText($_.FullName, $new, $utf8NoBom)
        Write-Host "Link ajustado: $($_.FullName)" -ForegroundColor Green
      }
    }
  }
}

Remove-Item -Recurse -Force ".next" -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "Site publico V5 com loja integrada instalado." -ForegroundColor Green
Write-Host "Editor: /painel/site" -ForegroundColor Cyan
Write-Host "Site publico: /site/[slug]" -ForegroundColor Cyan
Write-Host "Loja antiga /loja/[slug] redireciona para /site/[slug]" -ForegroundColor Cyan
Write-Host "Agora rode: npm run build" -ForegroundColor Yellow
